import java.io.IOException;
import java.util.Scanner;

public class CommandInjectionExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a directory name to list its contents: ");
        String directoryName = scanner.nextLine();

        try {
            String command = "ls " + directoryName; // Unsafe concatenation of user input
            Process process = Runtime.getRuntime().exec(command);

            Scanner processOutput = new Scanner(process.getInputStream());
            while (processOutput.hasNextLine()) {
                System.out.println(processOutput.nextLine());
            }

        } catch (IOException e) {
            e.printStackTrace();
        }

        scanner.close();
    }
}

